// ============================================================
// REEL CREATOR — Step 1
// Parse IDEA, call GPT-4o for production spec,
// scan folder, score clips via Vision, generate VO audio.
// ============================================================
const fs   = require('fs');
const path = require('path');
const { execSync } = require('child_process');

const input   = $input.item.json;
const ideaRaw = (input.Body || '').replace(/^IDEA:\s*/i, '').trim();

const OPENAI_KEY  = process.env.OPENAI_API_KEY       || $env.OPENAI_API_KEY;
const TWILIO_SID  = process.env.TWILIO_ACCOUNT_SID   || $env.TWILIO_ACCOUNT_SID;
const TWILIO_TOK  = process.env.TWILIO_AUTH_TOKEN     || $env.TWILIO_AUTH_TOKEN;
const TWILIO_FROM = process.env.TWILIO_WHATSAPP_FROM  || $env.TWILIO_WHATSAPP_FROM || 'whatsapp:+14155238886';
const TWILIO_TO   = process.env.TWILIO_WHATSAPP_TO    || $env.TWILIO_WHATSAPP_TO;

async function wa(msg) {
  const creds = Buffer.from(TWILIO_SID + ':' + TWILIO_TOK).toString('base64');
  await fetch('https://api.twilio.com/2010-04-01/Accounts/' + TWILIO_SID + '/Messages.json', {
    method: 'POST',
    headers: { 'Authorization': 'Basic ' + creds, 'Content-Type': 'application/x-www-form-urlencoded' },
    body: new URLSearchParams({ From: TWILIO_FROM, To: TWILIO_TO, Body: msg }).toString(),
  });
}

await wa('\ud83c\udfac Got your idea! Analysing and selecting clips\u2026 give me 2–3 mins.');

// --- Step 1: GPT-4o interprets the idea ---
const specRes = await fetch('https://api.openai.com/v1/chat/completions', {
  method: 'POST',
  headers: { 'Authorization': 'Bearer ' + OPENAI_KEY, 'Content-Type': 'application/json' },
  body: JSON.stringify({
    model: 'gpt-4o',
    response_format: { type: 'json_object' },
    messages: [
      { role: 'system', content: 'You are the creative director for this creator, a bold sensual lifestyle creator. Interpret reel ideas into precise production specs. Return only valid JSON.' },
      { role: 'user', content: 'Interpret this reel idea and return a JSON production spec:\n\nIdea: "' + ideaRaw + '"\n\nReturn exactly this JSON structure:\n{\n  "folder": "<one of: dance|fits|yoga pants|coffee|concerts|nature|house|lifestyle|fam|ranty|pov&jokes>",\n  "duration": <integer 15-60>,\n  "mood": "<string>",\n  "style": "<one of: slow_burn|smooth|energetic|dramatic>",\n  "needsVO": <true|false based on whether user said VO or voiceover>,\n  "voiceoverScript": "<if needsVO: write a poetic 40-60 word script in creator voice; else null>",\n  "maxClips": <integer 3-8>,\n  "musicMood": "<describe the energy and vibe of ideal background music>",\n  "musicSuggestion": "<specific song title by artist that matches the mood perfectly>"\n}' }
    ],
    max_tokens: 700,
  })
});
const specData = await specRes.json();
const spec = JSON.parse(specData.choices[0].message.content);
const { folder, duration, mood, style, needsVO, voiceoverScript, maxClips, musicMood, musicSuggestion } = spec;

console.log('[REEL] Spec:', JSON.stringify(spec));

// --- Step 2: Scan folder for video files ---
const contentBase = 'YOUR_CONTENT_FOLDER';
const folderPath  = path.join(contentBase, folder);
let videoFiles    = [];

if (fs.existsSync(folderPath)) {
  videoFiles = fs.readdirSync(folderPath)
    .filter(f => /\.(mp4|mov|avi|mkv|webm|m4v)$/i.test(f))
    .map(f => path.join(folderPath, f));
}

if (videoFiles.length === 0) {
  await wa('\u274c No videos found in ' + folder + '/ for: "' + ideaRaw + '"\n\nDrop some ' + folder + ' clips into YOUR_CONTENT_FOLDER\\' + folder + '\\ and try again.');
  return { action: 'no_clips', folder, ideaRaw };
}

console.log('[REEL] Found ' + videoFiles.length + ' video files in ' + folder + '/');

// --- Step 3: Score clips via GPT-4o Vision (frame extract) ---
const tempDir = 'YOUR_CONTENT_FOLDER\\scripts\\_temp';
if (!fs.existsSync(tempDir)) fs.mkdirSync(tempDir, { recursive: true });

const scored  = [];
const toCheck = Math.min(videoFiles.length, 12); // Cap at 12 to keep cost low

for (let i = 0; i < toCheck; i++) {
  const vPath     = videoFiles[i];
  const framePath = path.join(tempDir, 'frame_' + i + '.jpg');
  try {
    const durRaw = execSync(
      'ffprobe -v error -show_entries format=duration -of default=noprint_wrappers=1:nokey=1 "' + vPath + '"',
      { timeout: 10000 }
    ).toString().trim();
    const midpoint = parseFloat(durRaw) / 2 || 2;
    execSync(
      'ffmpeg -y -ss ' + midpoint + ' -i "' + vPath + '" -vframes 1 -q:v 3 "' + framePath + '"',
      { timeout: 15000 }
    );
    if (fs.existsSync(framePath)) {
      const b64      = fs.readFileSync(framePath).toString('base64');
      const scoreRes = await fetch('https://api.openai.com/v1/chat/completions', {
        method: 'POST',
        headers: { 'Authorization': 'Bearer ' + OPENAI_KEY, 'Content-Type': 'application/json' },
        body: JSON.stringify({
          model: 'gpt-4o',
          response_format: { type: 'json_object' },
          messages: [{ role: 'user', content: [
            { type: 'image_url', image_url: { url: 'data:image/jpeg;base64,' + b64 } },
            { type: 'text', text: 'Rate this clip for a reel with concept: "' + ideaRaw + '" (mood: ' + mood + ', style: ' + style + ').\nReturn only JSON: {"score":1-10,"reason":"<10 words>"}' }
          ]}],
          max_tokens: 80,
        })
      });
      const sd = await scoreRes.json();
      const sv = JSON.parse(sd.choices[0].message.content);
      scored.push({ path: vPath, score: sv.score || 5, reason: sv.reason || '' });
      try { fs.unlinkSync(framePath); } catch(e) {}
    } else {
      scored.push({ path: vPath, score: 5, reason: 'frame extract failed' });
    }
  } catch(e) {
    console.log('[REEL] Frame/score error clip ' + i + ':', e.message);
    scored.push({ path: vPath, score: 5, reason: 'error' });
  }
}

// If there are more files than we checked, add them with default score
for (let i = toCheck; i < videoFiles.length; i++) {
  scored.push({ path: videoFiles[i], score: 4, reason: 'not analysed' });
}

scored.sort((a, b) => b.score - a.score);
const selectedClips = scored.slice(0, maxClips || 5).map(c => c.path);
console.log('[REEL] Selected ' + selectedClips.length + ' clips');

// --- Step 4: Generate voiceover audio ---
let voiceoverAudioPath = null;
if (needsVO && voiceoverScript) {
  const ttsRes = await fetch('https://api.openai.com/v1/audio/speech', {
    method: 'POST',
    headers: { 'Authorization': 'Bearer ' + OPENAI_KEY, 'Content-Type': 'application/json' },
    body: JSON.stringify({
      model: 'tts-1-hd',
      input: voiceoverScript,
      voice: 'nova',  // Warm, confident, feminine
      response_format: 'mp3',
      speed: 0.92,    // Slightly slower = more sensual/deliberate
    })
  });
  if (ttsRes.ok) {
    const audioBuf = Buffer.from(await ttsRes.arrayBuffer());
    voiceoverAudioPath = path.join(tempDir, 'vo_' + Date.now() + '.mp3');
    fs.writeFileSync(voiceoverAudioPath, audioBuf);
    console.log('[REEL] Voiceover generated:', voiceoverAudioPath);
  } else {
    console.log('[REEL] TTS failed:', await ttsRes.text());
  }
}

// --- Step 5: Save args + return ---
const timestamp   = Date.now();
const reviewDir   = 'YOUR_VAULT_FOLDER\\reel_review';
if (!fs.existsSync(reviewDir)) fs.mkdirSync(reviewDir, { recursive: true });

const outputPath  = path.join(reviewDir, 'reel_p1_' + timestamp + '.mp4');
const reelArgs    = {
  clips:           selectedClips,
  duration,
  outputPath,
  voiceoverPath:   voiceoverAudioPath,
  voiceoverScript: needsVO ? (voiceoverScript || '') : '',
  style,
  idea:            ideaRaw,
  mood,
  musicSuggestion,
  musicMood,
  timestamp,
};

const argsFile = 'YOUR_CONTENT_FOLDER\\scripts\\reel_args_temp.json';
fs.writeFileSync(argsFile, JSON.stringify(reelArgs, null, 2));

return {
  argsFile,
  outputPath,
  selectedClipsCount: selectedClips.length,
  voiceoverReady:     !!voiceoverAudioPath,
  idea:               ideaRaw,
  musicSuggestion,
  musicMood,
  duration,
  style,
  mood,
  voiceoverScript:    needsVO ? voiceoverScript : '',
};

// ============================================================
// REEL CREATOR — Step 3
// Parse Python output, upload to Imgur, send WhatsApp preview.
// ============================================================
const fs   = require('fs');
const prev = $input.item.json;

// Parse Python script stdout
let reelResult = {};
try {
  const stdout = prev.stdout || '';
  const jsonLine = stdout.split('\n').reverse().find(l => l.trim().startsWith('{'));
  reelResult = JSON.parse(jsonLine || '{}');
} catch(e) {
  console.log('[UPLOAD] Could not parse reel result:', e.message);
}

const TWILIO_SID      = process.env.TWILIO_ACCOUNT_SID    || $env.TWILIO_ACCOUNT_SID;
const TWILIO_TOK      = process.env.TWILIO_AUTH_TOKEN      || $env.TWILIO_AUTH_TOKEN;
const TWILIO_FROM     = process.env.TWILIO_WHATSAPP_FROM   || $env.TWILIO_WHATSAPP_FROM || 'whatsapp:+14155238886';
const TWILIO_TO       = process.env.TWILIO_WHATSAPP_TO     || $env.TWILIO_WHATSAPP_TO;
const CLOUDINARY_CLOUD_NAME    = process.env.CLOUDINARY_CLOUD_NAME    || $env.CLOUDINARY_CLOUD_NAME;
  const CLOUDINARY_UPLOAD_PRESET = process.env.CLOUDINARY_UPLOAD_PRESET || $env.CLOUDINARY_UPLOAD_PRESET;

async function wa(msg) {
  const creds = Buffer.from(TWILIO_SID + ':' + TWILIO_TOK).toString('base64');
  await fetch('https://api.twilio.com/2010-04-01/Accounts/' + TWILIO_SID + '/Messages.json', {
    method: 'POST',
    headers: { 'Authorization': 'Basic ' + creds, 'Content-Type': 'application/x-www-form-urlencoded' },
    body: new URLSearchParams({ From: TWILIO_FROM, To: TWILIO_TO, Body: msg }).toString(),
  });
}

if (!reelResult.success) {
  const errMsg = '\u274c Reel assembly failed.\n\nError: ' + (prev.stderr || 'Unknown').substring(0, 300);
  await wa(errMsg);
  return { action: 'failed', error: errMsg };
}

const { outputPath, duration, sizeMB, clipsUsed, voiceoverAdded, captionsAdded } = reelResult;

// Upload to Imgur for WhatsApp preview
let previewUrl = null;
try {
  const buf = fs.readFileSync(outputPath);
  const b64 = buf.toString('base64');
  const cloudRes = await fetch('https://api.cloudinary.com/v1_1/' + CLOUDINARY_CLOUD_NAME + '/auto/upload', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ file: 'data:video/mp4;base64,' + b64, upload_preset: CLOUDINARY_UPLOAD_PRESET }),
  });
  const cloudData = await cloudRes.json();
  previewUrl = cloudData?.secure_url || null;
  console.log('[CLOUDINARY] Upload URL:', previewUrl);
} catch(e) {
  console.log('[UPLOAD] Imgur failed:', e.message);
}

// Save reel to pending_reels.json for POST command handling
const pendingReelsPath = 'YOUR_CONTENT_FOLDER\\scripts\\pending_reels.json';
let pendingReels = {};
try {
  if (require('fs').existsSync(pendingReelsPath)) {
    pendingReels = JSON.parse(fs.readFileSync(pendingReelsPath, 'utf8'));
  }
} catch(e) {}

const reelId = 'reel_p1_' + (prev.timestamp || Date.now());
pendingReels[reelId] = {
  id:              reelId,
  outputPath,
  idea:            prev.idea || '',
  musicSuggestion: prev.musicSuggestion || '',
  musicMood:       prev.musicMood || '',
  voiceoverScript: prev.voiceoverScript || '',
  duration,
  clipsUsed,
  status:          'pending_review',
  createdAt:       new Date().toISOString(),
};
fs.writeFileSync(pendingReelsPath, JSON.stringify(pendingReels, null, 2));

// Format WhatsApp message
const msg = [
  '\ud83c\udfac content_creator \u2014 Reel Ready!',
  '',
  '\u23f1 ' + duration + 's  |  \ud83c\udfac ' + clipsUsed + ' clips  |  \ud83d� 9:16',
  voiceoverAdded  ? '\ud83c� Voiceover: \u2705' : '\ud83c� Voiceover: none',
  captionsAdded   ? '\ud83d� Captions: \u2705'   : '\ud83d� Captions: none',
  '',
  '\ud83c� Music suggestion:',
  prev.musicSuggestion || 'Check mood: ' + (prev.musicMood || ''),
  '(Add in-app when posting)',
  '',
  previewUrl ? ('\ud83d\udce5 Preview: ' + previewUrl) : ('\ud83d\udcc1 Saved: ' + outputPath),
  '',
  'Reply:',
  'POST \u2014 post it to Instagram + Threads',
  'REDO <changes> \u2014 regenerate with tweaks',
  'SKIP \u2014 discard this reel',
].join('\n');

await wa(msg);

return {
  action:      'reel_ready',
  reelId,
  outputPath,
  previewUrl,
  duration,
  sizeMB,
  idea:        prev.idea,
  musicSuggestion: prev.musicSuggestion,
};
